 1→import { useCallback, useEffect, useState } from 'react';
 2→import { storageGet, storageSet } from '../utils/storage';
 3→
 4→type ThemePreference = 'dark' | 'light' | 'system';
 5→type ResolvedTheme = 'dark' | 'light';
 6→
 7→const STORAGE_KEY = 'theme';
 8→
 9→function isThemePreference(value: unknown): value is ThemePreference {
10→  return value === 'dark' || value === 'light' || value === 'system';
11→}
12→
13→function getSystemTheme(): ResolvedTheme {
14→  return window.matchMedia('(prefers-color-scheme: light)').matches
15→    ? 'light'
16→    : 'dark';
17→}
18→
19→function resolveTheme(preference: ThemePreference): ResolvedTheme {
20→  return preference === 'system' ? getSystemTheme() : preference;
21→}
22→
23→function loadPreference(): ThemePreference {
24→  return storageGet(STORAGE_KEY, isThemePreference) ?? 'dark';
25→}
26→
27→function applyTheme(theme: ResolvedTheme) {
28→  document.documentElement.setAttribute('data-theme', theme);
29→}
30→
31→export function useTheme() {
32→  const [preference, setPreference] = useState<ThemePreference>(loadPreference);
33→  const [resolved, setResolved] = useState<ResolvedTheme>(() =>
34→    resolveTheme(loadPreference()));
35→
36→  useEffect(() => {
37→    const r = resolveTheme(preference);
38→    setResolved(r);
39→    applyTheme(r);
40→  }, [preference]);
41→
42→  useEffect(() => {
43→    if (preference !== 'system') return;
44→
45→    const mql = window.matchMedia('(prefers-color-scheme: light)');
46→    const handler = () => {
47→      const r = resolveTheme('system');
48→      setResolved(r);
49→      applyTheme(r);
50→    };
51→    mql.addEventListener('change', handler);
52→    return () => mql.removeEventListener('change', handler);
53→  }, [preference]);
54→
55→  const setTheme = useCallback((value: ThemePreference) => {
56→    setPreference(value);
57→    storageSet(STORAGE_KEY, value);
58→  }, []);
59→
60→  return {
61→    preference,
62→    resolved,
63→    setTheme,
64→  };
65→}
