  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { isStringArray, storageGet, storageSet } from '../../utils/storage';
 13→import { ActionPanel } from '../action_panel/action_panel';
 14→import type { DropdownSection } from '../action_panel/actions_dropdown';
 15→import { EmptyState } from '../empty_state/empty_state';
 16→import { HUDContainer } from '../hud/hud_container';
 17→import { Kbd } from '../kbd/kbd';
 18→import { SearchBar } from '../search_bar/search_bar';
