 28→  return (
 29→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 30→      <path
 31→        d="M3.5 8.5L6.5 11.5L12.5 4.5"
 32→        stroke="currentColor"
 33→        strokeWidth="1.5"
 34→        strokeLinecap="round"
 35→        strokeLinejoin="round"
 36→      />
 37→    </svg>
 38→  );
 39→}
 40→
 41→function SearchEmptyIcon() {
 42→  return (
 43→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 44→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 45→      <line
 46→        x1="30"
 47→        y1="30"
 48→        x2="42"
 49→        y2="42"
 50→        stroke="currentColor"
 51→        strokeWidth="3"
 52→        strokeLinecap="round"
 53→      />
 54→    </svg>
 55→  );
