 57→
 58→function loadRecentEmojis(): string[] {
 59→  return storageGet(STORAGE_KEY, isStringArray) ?? [];
 60→}
 61→
 62→interface EmojiSection {
 63→  title: string;
 64→  emojis: EmojiEntry[];
 65→}
 66→
 67→const FILTER_SECTIONS: SearchDropdownSection[] = [
 68→  {
 69→    options: [
 70→      {
 71→        label: 'All',
 72→        value: 'all',
 73→      },
 74→    ],
 75→  },
 76→  {
 77→    title: 'Category',
 78→    options: EMOJI_CATEGORIES.map(c => ({
 79→      label: c.label,
 80→      value: c.value,
 81→    })),
 82→  },
 83→];
