 85→export function EmojiPickerView() {
 86→  const nav = useNavigation();
 87→  const [query, setQuery] = useState('');
 88→  const [filterValue, setFilterValue] = useState('all');
 89→  const [activeIndex, setActiveIndex] = useState(0);
 90→  const [actionsOpen, setActionsOpen] = useState(false);
 91→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
 92→  const { items: hudItems, show: showHUD } = useHUD();
 93→  const containerRef = useRef<HTMLDivElement>(null);
 94→
 95→  const emojiLookup = useMemo(() => {
 96→    const map = new Map<string, EmojiEntry>();
 97→    for (const e of MOCK_EMOJIS) {
 98→      map.set(e.char, e);
 99→    }
100→    return map;
101→  }, []);
102→
103→  const recentEmojis = useMemo(
104→    () =>
105→      recentChars
106→        .map(char => emojiLookup.get(char))
107→        .filter((e): e is EmojiEntry => e !== undefined),
108→    [
109→      recentChars,
110→      emojiLookup,
111→    ],
112→  );
113→
114→  const filtered = useMemo(() => {
115→    let emojis = MOCK_EMOJIS;
116→    if (filterValue !== 'all') {
117→      emojis = emojis.filter(e => e.category === filterValue);
118→    }
119→    if (query) {
120→      const lower = query.toLowerCase();
121→      emojis = emojis.filter(
122→        e =>
123→          e.name.toLowerCase().includes(lower) ||
124→          e.keywords.some(k => k.includes(lower)) ||
125→          e.char === query,
126→      );
127→    }
128→    return emojis;
129→  }, [
130→    query,
131→    filterValue,
132→  ]);
133→
134→  const sections = useMemo(() => {
135→    const result: EmojiSection[] = [];
136→
137→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
138→      result.push({
139→        title: 'Recently Used',
140→        emojis: recentEmojis,
141→      });
142→    }
143→
144→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
145→    for (const emoji of filtered) {
146→      const existing = grouped.get(emoji.category);
147→      if (existing) {
148→        existing.push(emoji);
149→      } else {
150→        grouped.set(emoji.category, [emoji]);
151→      }
152→    }
153→
154→    for (const cat of EMOJI_CATEGORY_ORDER) {
155→      const items = grouped.get(cat);
156→      if (items && items.length > 0) {
157→        result.push({
158→          title: EMOJI_CATEGORY_LABELS[cat],
159→          emojis: items,
160→        });
161→      }
162→    }
163→
164→    return result;
165→  }, [
166→    filtered,
167→    query,
168→    filterValue,
169→    recentEmojis,
170→  ]);
171→
172→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
173→  const totalCount = flatEmojis.length;
174→
175→  useEffect(() => {
176→    if (totalCount === 0) {
177→      setActiveIndex(0);
178→    } else if (activeIndex >= totalCount) {
179→      setActiveIndex(totalCount - 1);
180→    }
181→  }, [
182→    totalCount,
183→    activeIndex,
184→  ]);
185→
186→  useEffect(() => {
187→    const container = containerRef.current;
188→    if (!container) return;
189→    const el = container.querySelector<HTMLElement>(
190→      `[data-emoji-index="${activeIndex}"]`,
191→    );
192→    el?.scrollIntoView({ block: 'nearest' });
193→  }, [activeIndex]);
194→
195→  const selectedEmoji = flatEmojis[activeIndex];
196→
197→  const addToRecent = useCallback((char: string) => {
198→    setRecentChars(prev => {
199→      const next = [
200→        char,
201→        ...prev.filter(c => c !== char),
202→      ].slice(0, MAX_RECENT);
203→      storageSet(STORAGE_KEY, next);
204→      return next;
205→    });
206→  }, []);
207→
208→  const handleCopyEmoji = useCallback(
209→    (emoji?: EmojiEntry) => {
210→      const target = emoji ?? selectedEmoji;
211→      if (!target) return;
212→      navigator.clipboard.writeText(target.char).catch(() => {});
213→      setActionsOpen(false);
214→      addToRecent(target.char);
215→      showHUD({
216→        icon: <CopyHUDIcon />,
217→        title: `Copied ${target.char}`,
218→      });
219→    },
220→    [
221→      selectedEmoji,
222→      showHUD,
223→      addToRecent,
224→    ],
225→  );
226→
227→  const handleQueryChange = useCallback((value: string) => {
228→    setQuery(value);
229→    setActiveIndex(0);
230→    setActionsOpen(false);
231→  }, []);
232→
233→  const handleFilterChange = useCallback((value: string) => {
234→    setFilterValue(value);
235→    setActiveIndex(0);
236→  }, []);
237→
238→  const toggleActions = useCallback(() => {
239→    setActionsOpen(prev => !prev);
240→  }, []);
241→
242→  const closeActions = useCallback(() => {
243→    setActionsOpen(false);
244→  }, []);
245→
246→  useKeyboardShortcut(
247→    {
248→      key: 'k',
249→      meta: true,
250→    },
251→    toggleActions,
252→  );
253→  useKeyboardShortcut(
254→    {
255→      key: 'c',
256→      meta: true,
257→    },
258→    () => handleCopyEmoji(),
259→  );
260→
261→  useEffect(() => {
262→    function handleKeyDown(e: KeyboardEvent) {
263→      if (totalCount === 0) return;
264→      if (actionsOpen) return;
265→      if (e.metaKey || e.ctrlKey || e.altKey) return;
266→
267→      const isTextInput =
268→        e.target instanceof HTMLInputElement ||
269→        e.target instanceof HTMLTextAreaElement;
270→
271→      switch (e.key) {
272→        case 'ArrowRight': {
273→          if (isTextInput) return;
274→          e.preventDefault();
275→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
276→          break;
277→        }
278→        case 'ArrowLeft': {
279→          if (isTextInput) return;
280→          e.preventDefault();
281→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
282→          break;
283→        }
284→        case 'ArrowDown': {
285→          e.preventDefault();
286→          setActiveIndex(prev => {
287→            const sectionInfo = getSectionInfo(prev);
288→            if (!sectionInfo) return prev;
289→            const { sectionStart, sectionLength } = sectionInfo;
290→            const posInSection = prev - sectionStart;
291→            const row = Math.floor(posInSection / COLUMNS);
292→            const col = posInSection % COLUMNS;
293→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
294→
295→            if (row + 1 < sectionRows) {
296→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
297→              return nextIdx < sectionStart + sectionLength
298→                ? nextIdx
299→                : sectionStart + sectionLength - 1;
300→            }
301→
302→            const nextSectionStart = sectionStart + sectionLength;
303→            if (nextSectionStart < totalCount) {
304→              const nextInfo = getSectionInfo(nextSectionStart);
305→              if (!nextInfo) return prev;
306→              const targetIdx = nextSectionStart + col;
307→              return targetIdx < nextSectionStart + nextInfo.sectionLength
308→                ? targetIdx
309→                : nextSectionStart + nextInfo.sectionLength - 1;
310→            }
311→
312→            return prev;
313→          });
314→          break;
315→        }
316→        case 'ArrowUp': {
317→          e.preventDefault();
318→          setActiveIndex(prev => {
319→            const sectionInfo = getSectionInfo(prev);
320→            if (!sectionInfo) return prev;
321→            const { sectionStart } = sectionInfo;
322→            const posInSection = prev - sectionStart;
323→            const row = Math.floor(posInSection / COLUMNS);
324→            const col = posInSection % COLUMNS;
325→
326→            if (row > 0) {
327→              return sectionStart + (row - 1) * COLUMNS + col;
328→            }
329→
330→            if (sectionStart > 0) {
331→              const prevSectionEnd = sectionStart - 1;
332→              const prevInfo = getSectionInfo(prevSectionEnd);
333→              if (!prevInfo) return prev;
334→              const prevSectionRows = Math.ceil(
335→                prevInfo.sectionLength / COLUMNS,
336→              );
337→              const lastRowStart =
338→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
339→              const targetIdx = lastRowStart + col;
340→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
341→                ? targetIdx
342→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
343→            }
344→
345→            return prev;
346→          });
347→          break;
348→        }
349→        case 'Enter': {
350→          e.preventDefault();
351→          handleCopyEmoji();
352→          break;
353→        }
354→      }
355→    }
356→
357→    window.addEventListener('keydown', handleKeyDown);
358→    return () => window.removeEventListener('keydown', handleKeyDown);
359→  }, [
360→    totalCount,
361→    actionsOpen,
362→    handleCopyEmoji,
363→    sections,
364→  ]);
365→
366→  const sectionBoundaries = useMemo(() => {
367→    const boundaries: {
368→      start: number;
369→      length: number;
370→    }[] = [];
371→    let offset = 0;
372→    for (const section of sections) {
373→      boundaries.push({
374→        start: offset,
375→        length: section.emojis.length,
376→      });
377→      offset += section.emojis.length;
378→    }
379→    return boundaries;
380→  }, [sections]);
381→
382→  function getSectionInfo(index: number) {
383→    for (const b of sectionBoundaries) {
384→      if (index >= b.start && index < b.start + b.length) {
385→        return {
386→          sectionStart: b.start,
387→          sectionLength: b.length,
388→        };
389→      }
390→    }
391→    return null;
392→  }
393→
394→  const dropdownSections: DropdownSection[] = useMemo(
395→    () => [
396→      {
397→        title: 'Actions',
398→        actions: [
399→          {
400→            label: 'Copy Emoji',
401→            shortcut: <Kbd keys={['↵']} />,
402→            onClick: () => handleCopyEmoji(),
403→          },
404→          {
405→            label: 'Copy to Clipboard',
406→            shortcut: (
407→              <Kbd
408→                keys={[
409→                  '⌘',
410→                  'C',
411→                ]}
412→              />
413→            ),
414→            onClick: () => handleCopyEmoji(),
415→          },
416→        ],
417→      },
418→    ],
419→    [handleCopyEmoji],
420→  );
421→
422→  const handleGridMouseOver = useCallback((
423→    e: React.MouseEvent<HTMLDivElement>,
424→  ) => {
425→    const target = (e.target as HTMLElement).closest<HTMLElement>(
426→      '[data-emoji-index]',
427→    );
428→    if (!target) return;
429→    const idx = Number(target.dataset.emojiIndex);
430→    if (!Number.isNaN(idx)) {
431→      setActiveIndex(idx);
432→    }
433→  }, []);
434→
435→  const activeDescendantId =
436→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
437→
438→  return (
439→    <>
440→      <SearchBar
441→        value={query}
442→        onChange={handleQueryChange}
443→        placeholder="Search Emoji..."
444→        activeDescendantId={activeDescendantId}
445→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
446→        dropdown={
447→          <SearchDropdown
448→            sections={FILTER_SECTIONS}
449→            value={filterValue}
450→            onChange={handleFilterChange}
451→          />
452→        }
453→      />
454→      <div className="command-palette__body">
455→        <div className="command-palette__list-container">
456→          {totalCount === 0 ? (
457→            <EmptyState
458→              icon={<SearchEmptyIcon />}
459→              title="No Emoji Found"
460→              description={
461→                query
462→                  ? 'Try a different search term'
463→                  : 'No emojis in this category'
464→              }
465→            />
466→          ) : (
467→            <div
468→              ref={containerRef}
469→              className="emoji-picker"
470→              role="listbox"
471→              id="emoji-grid"
472→              aria-label="Emoji list"
473→              aria-activedescendant={activeDescendantId}
474→              onMouseOver={handleGridMouseOver}
475→            >
476→              {(() => {
477→                let globalIndex = 0;
478→                return sections.map(section => (
479→                  <div key={section.title} className="emoji-picker__section">
480→                    <div className="emoji-picker__section-header">
481→                      {section.title}
482→                    </div>
483→                    <div className="emoji-picker__grid">
484→                      {section.emojis.map(emoji => {
485→                        const idx = globalIndex++;
486→                        const isActive = idx === activeIndex;
487→                        return (
488→                          <div
489→                            key={`${section.title}-${emoji.char}`}
490→                            id={`emoji-item-${idx}`}
491→                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
492→                            role="option"
493→                            aria-selected={isActive}
494→                            aria-label={emoji.name}
495→                            data-emoji-index={idx}
496→                            onClick={() => {
497→                              setActiveIndex(idx);
498→                              handleCopyEmoji(emoji);
499→                            }}
500→                          >
501→                            {emoji.char}
502→                          </div>
503→                        );
504→                      })}
505→                    </div>
506→                  </div>
507→                ));
508→              })()}
509→            </div>
510→          )}
511→        </div>
512→      </div>
513→      <ActionPanel
514→        contextLabel="Emoji"
515→        actions={[
516→          {
517→            label: selectedEmoji ? `Copy ${selectedEmoji.char}` : 'Copy Emoji',
518→            shortcut: <Kbd keys={['↵']} />,
519→          },
520→          {
521→            label: 'Actions',
522→            shortcut: (
523→              <Kbd
524→                keys={[
525→                  '⌘',
526→                  'K',
527→                ]}
528→              />
529→            ),
530→            onClick: toggleActions,
531→          },
532→        ]}
533→        dropdownOpen={actionsOpen}
534→        dropdownSections={dropdownSections}
535→        onDropdownClose={closeActions}
536→      />
537→      <HUDContainer items={hudItems} />
538→    </>
539→  );
540→}
