  1→import { useCallback, useMemo, useState } from 'react';
  2→import { type ExtensionEntry, MOCK_EXTENSIONS } from '../../data/settings_data';
  3→import { useAlert } from '../../hooks/use_alert';
  4→import { useHUD } from '../../hooks/use_hud';
  5→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
  6→import { useNavigation } from '../../hooks/use_navigation';
  7→import { useTheme } from '../../hooks/use_theme';
  8→import {
  9→  isRecord,
 10→  storageGet,
 11→  storageRemove,
 12→  storageSet,
