 30→const SETTINGS_TABS: SettingsTab[] = [
 31→  'general',
 32→  'extensions',
 33→  'advanced',
 34→];
 35→
 36→function isSettingsTab(value: string): value is SettingsTab {
 37→  return SETTINGS_TABS.includes(value as SettingsTab);
 38→}
