 40→interface GeneralSettings {
 41→  appearance: string;
 42→  windowWidth: string;
 43→  showRecentApps: boolean;
 44→  showDock: boolean;
 45→  fontSize: string;
 46→}
 47→
 48→const SETTINGS_STORAGE_KEY = 'settings-general';
 49→const EXTENSIONS_STORAGE_KEY = 'settings-extensions';
 50→
 51→const DEFAULT_SETTINGS: GeneralSettings = {
 52→  appearance: 'dark',
 53→  windowWidth: 'medium',
 54→  showRecentApps: true,
 55→  showDock: true,
 56→  fontSize: 'default',
 57→};
 58→
 59→function isGeneralSettings(value: unknown): value is GeneralSettings {
 60→  if (!isRecord(value)) return false;
 61→  return (
 62→    typeof value.appearance === 'string' &&
 63→    typeof value.windowWidth === 'string' &&
 64→    typeof value.showRecentApps === 'boolean' &&
 65→    typeof value.showDock === 'boolean' &&
 66→    typeof value.fontSize === 'string'
 67→  );
 68→}
 69→
 70→function isExtensionStates(value: unknown): value is Record<string, boolean> {
 71→  if (!isRecord(value)) return false;
 72→  return Object.values(value).every(v => typeof v === 'boolean');
 73→}
 74→
 75→function loadSettings(themePreference: string): GeneralSettings {
 76→  const stored = storageGet(SETTINGS_STORAGE_KEY, isGeneralSettings);
 77→  if (stored)
 78→    return {
 79→      ...stored,
 80→      appearance: themePreference,
 81→    };
 82→  return {
 83→    ...DEFAULT_SETTINGS,
 84→    appearance: themePreference,
 85→  };
 86→}
 87→
 88→function loadExtensions(): ExtensionEntry[] {
 89→  const states = storageGet(EXTENSIONS_STORAGE_KEY, isExtensionStates);
 90→  return MOCK_EXTENSIONS.map(ext => ({
 91→    ...ext,
 92→    enabled: states ? (states[ext.id] ?? ext.enabled) : ext.enabled,
 93→  }));
 94→}
