135→const PIN_STATE_KEY = 'clipboard-pins';
136→const DELETED_KEY = 'clipboard-deleted';
137→
138→function isPinState(value: unknown): value is Record<string, boolean> {
139→  if (!isRecord(value)) return false;
140→  return Object.values(value).every(v => typeof v === 'boolean');
141→}
142→
143→function loadInitialEntries(): ClipboardEntry[] {
144→  const pinState = storageGet(PIN_STATE_KEY, isPinState) ?? {};
145→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
146→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
147→    ...e,
148→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
149→  }));
150→}
151→
152→function saveEntryState(entries: ClipboardEntry[]) {
153→  const pinState: Record<string, boolean> = {};
154→  for (const e of entries) {
155→    pinState[e.id] = e.pinned;
156→  }
157→  storageSet(PIN_STATE_KEY, pinState);
158→
159→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
160→  const currentIds = new Set(entries.map(e => e.id));
161→  const deleted = [...allIds].filter(id => !currentIds.has(id));
162→  storageSet(DELETED_KEY, deleted);
163→}
