 90→function truncateContent(content: string, maxLength: number): string {
 91→  const singleLine = content.replace(/\n/g, ' ');
 92→  if (singleLine.length <= maxLength) return singleLine;
 93→  return singleLine.slice(0, maxLength) + '\u2026';
 94→}
