 96→const SNIPPETS_KEY = 'snippets';
 97→
 98→interface StoredSnippet {
 99→  id: string;
100→  name: string;
101→  keyword: string;
102→  content: string;
103→  category: string;
104→  tags: {
105→    text: string;
106→    color?: string;
107→  }[];
108→  createdAt: string;
109→}
110→
111→function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
112→  if (!Array.isArray(value)) return false;
113→  return value.every(
114→    v =>
115→      typeof v === 'object' &&
116→      v !== null &&
117→      typeof (v as StoredSnippet).id === 'string' &&
118→      typeof (v as StoredSnippet).name === 'string' &&
119→      typeof (v as StoredSnippet).createdAt === 'string',
120→  );
121→}
122→
123→function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
124→  return entries.map(e => ({
125→    ...e,
126→    createdAt: e.createdAt.toISOString(),
127→  }));
128→}
129→
130→const TAG_COLORS = new Set<string>([
131→  'blue',
132→  'green',
133→  'orange',
134→  'red',
135→  'purple',
136→  'yellow',
137→]);
138→
139→function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
140→  return stored.map(s => ({
141→    ...s,
142→    category: isSnippetCategory(s.category) ? s.category : 'general',
143→    tags: s.tags.map(t => ({
144→      text: t.text,
145→      color:
146→        t.color && TAG_COLORS.has(t.color) ? (t.color as TagColor) : undefined,
147→    })),
148→    createdAt: new Date(s.createdAt),
149→  }));
150→}
151→
152→function loadSnippets(): SnippetEntry[] {
153→  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
154→  if (stored) return deserializeEntries(stored);
155→  return MOCK_SNIPPET_ENTRIES;
156→}
157→
158→function saveSnippets(entries: SnippetEntry[]) {
159→  storageSet(SNIPPETS_KEY, serializeEntries(entries));
160→}
